module Mux_4x1
(
    input [1:0] sel,
    input in_0,
    input in_1,
    input in_2,
    input in_3,
    output reg out
);
    always @ (*) begin
        case (sel)
            2'h0: out = in_0;
            2'h1: out = in_1;
            2'h2: out = in_2;
            2'h3: out = in_3;
            default:
                out = 'h0;
        endcase
    end
endmodule


// Register for storing large constants.
// There is a 1-bit command describing this register. 
// In this way, 15 bits can be stored (the 16th bit 
// activates the writing of this register and therefore 
// is always one). The 16th bit will be set according 
// to the 'immediate extend mode' (iem).
module ImReg (
  input en, // enables storage
  input [1:0] iem, // immediate extend mode (0: sign extend; 1: extend with 0, 2:extend with S0, 3:extend with D0)
  input C,
  input [15:0] inst, // the current instruction
  output [15:0] imm // The constant of register contents and bit 8.

);
  wire [14:0] s0;
  wire [14:0] s1;
  wire s2;
  wire s3;
  wire s4;
  wire s5;
  assign s2 = inst[0];
  assign s3 = inst[4];
  assign s0 = inst[14:0];
  // imm
  DIG_Register_BUS #(
    .Bits(15)
  )
  DIG_Register_BUS_i0 (
    .D( s0 ),
    .C( C ),
    .en( en ),
    .Q( s1 )
  );
  assign s5 = s1[14];
  Mux_4x1 Mux_4x1_i1 (
    .sel( iem ),
    .in_0( s5 ),
    .in_1( 1'b0 ),
    .in_2( s2 ),
    .in_3( s3 ),
    .out( s4 )
  );
  assign imm[14:0] = s1;
  assign imm[15] = s4;
endmodule
module muxEncoder
  (
    input a,
    input b,
    input c,
    input d,
    output reg [1:0]Q
  );

  always @ (a,b,c,d)
  begin

    Q[0] = | d | b ;
    Q[1] = | d | c ;

  end
endmodule


module Mux_4x1_NBits #(
    parameter Bits = 2
)
(
    input [1:0] sel,
    input [(Bits - 1):0] in_0,
    input [(Bits - 1):0] in_1,
    input [(Bits - 1):0] in_2,
    input [(Bits - 1):0] in_3,
    output reg [(Bits - 1):0] out
);
    always @ (*) begin
        case (sel)
            2'h0: out = in_0;
            2'h1: out = in_1;
            2'h2: out = in_2;
            2'h3: out = in_3;
            default:
                out = 'h0;
        endcase
    end
endmodule

module lfsr_RandomNumberGen (
    input  [4:0] adrrIn,
    input  [7:0] dataIn,
    input         ioW,
    input         clk,
    input  [4:0] SeedAdr,
    input  [4:0] RngAdr,
    output [15:0] Out
);

    reg [7:0] seed_reg;
    reg [7:0] lfsr    ;

    wire seed_wr  = ioW && (adrrIn == SeedAdr);
    wire seed_rd  =  (adrrIn == SeedAdr);
    wire rng_rd   =  (adrrIn == RngAdr);

    // 8-bit maximal-length taps
    // polynomial: x^8 + x^6 + x^5 + x^4 + 1
    wire feedback = lfsr[7] ^ lfsr[5] ^ lfsr[4] ^ lfsr[3];

    always @(posedge clk) begin
        if (seed_wr) begin
            seed_reg <= dataIn[7:0];
            lfsr <= (dataIn[7:0] == 8'h00) ? 8'h01 : dataIn[7:0];
        end else begin
            lfsr <= {lfsr[6:0], feedback};
        end
    end

    assign Out = seed_rd ? {8'h00, seed_reg} :
                 rng_rd  ? {8'h00, lfsr}     :
                           16'h0000;

endmodule
module RegisterBlock (
    input  [15:0] DataIn,
    input         WE,
    input         clk,
    input  [3:0]  src,
    input  [3:0]  Dest,
    output [15:0] RDest,
    output [15:0] Rsrc
  );

  reg [15:0] regs [0:15];

  always @(negedge clk )
  begin

    if (WE)
    begin
      regs[Dest] <= DataIn;
    end
  end

  // read ports
  assign Rsrc  = regs[src];
  assign RDest = regs[Dest];

endmodule

module Alu (
    input [15:0] A,
    input [15:0] B,
    input carryIn,
    input [4:0] AluOp,
    output [15:0] Out,
    output Neg,
    output Zero,
    output CarryOut
  );
  wire use_carry;
  wire [3:0] sel;
  reg  [15:0] out_r;
  reg         carry_r;
  reg  [16:0] math_ext;

  assign use_carry = AluOp[4] & carryIn;
  assign sel = AluOp[3:0];

  always @(*)
  begin
    out_r   = 16'h0000;
    carry_r = 1'b0;
    math_ext = 17'h00000;

    case (sel)
      4'h0:
      begin // pass B through
        out_r = B;
      end

      4'h1:
      begin // add with optional carry
        math_ext = {1'b0, A} + {1'b0, B} + {{16{1'b0}}, use_carry};
        out_r    = math_ext[15:0];
        carry_r  = math_ext[16];
      end

      4'h2:
      begin // subtract with optional carry
        math_ext = {1'b0, A} - {1'b0, B} - {{16{1'b0}}, use_carry};
        out_r    = math_ext[15:0];
        carry_r  = math_ext[16];
      end

      4'h3:
      begin // bitwise AND
        out_r = A & B;
      end

      4'h4:
      begin // bitwise OR
        out_r = A | B;
      end

      4'h5:
      begin // bitwise XOR
        out_r = A ^ B;
      end

      4'h6:
      begin // bitwise NOT
        out_r = ~A;
      end

      4'h7:
      begin // negate (two's complement)
        math_ext = {1'b0, 16'h0000} - {1'b0, A};
        out_r    = math_ext[15:0];
      end

      4'h8:
      begin // shift left with optional carry
        out_r   = {A[14:0], use_carry};
        carry_r = A[15];
      end

      4'h9:
      begin // shift right with optional carry
        out_r   = {use_carry, A[15:1]};
        carry_r = A[0];
      end

      4'hA:
      begin // arithmetic shift right with optional carry
        out_r   = {A[15], A[15], A[14:1]};
        carry_r = A[0];
      end

      4'hB:
      begin // swap bytes
        out_r = {A[7:0], A[15:8]};
      end

      4'hC:
      begin // swap nibbles
        out_r = {A[11:8], A[15:12], A[3:0], A[7:4]};
      end

      default:
      begin // default to zero output
        out_r   = 16'h0000;
        carry_r = 1'b0;
      end
    endcase
  end

  assign Out      = out_r;
  assign CarryOut = carry_r;
  assign Neg      = out_r[15];
  assign Zero     = ~|out_r;
endmodule


module CompUnsigned #(
    parameter Bits = 1
)
(
    input [(Bits -1):0] a,
    input [(Bits -1):0] b,
    output \> ,
    output \= ,
    output \<
);
    assign \> = a > b;
    assign \= = a == b;
    assign \< = a < b;
endmodule


